import React, { useEffect, useState } from "react";
import axios from "axios";

function BlockchainView() {
    const [agreements, setAgreements] = useState([]);
    const [payments, setPayments] = useState([]);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            const token = localStorage.getItem("token");

const agreementResponse = await axios.get(
    "https://rental-management-system-backend-0h42.onrender.com/agreements/",
    {
        headers: {
            Authorization: `Bearer ${token}`
        }
    }
);

const paymentResponse = await axios.get(
    "https://rental-management-system-backend-0h42.onrender.com/payments/",
    {
        headers: {
            Authorization: `Bearer ${token}`
        }
    }
);

            console.log(agreementResponse.data);
            console.log(paymentResponse.data);

            setAgreements(agreementResponse.data);
            setPayments(paymentResponse.data);

        } catch (error) {
            console.error(error);
            alert("Failed to load blockchain records");
        }
    };

    return (
        <div className="container mt-5">
            <h2>Blockchain Verification</h2>

            <h4 className="mt-4">Agreement Hashes</h4>

            <table className="table table-bordered">
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Blockchain Hash</th>
                    </tr>
                </thead>
                <tbody>
                    {agreements.map((agreement) => (
                        <tr key={agreement.id}>
                            <td>{agreement.id}</td>
                            <td>{agreement.blockchain_hash}</td>
                        </tr>
                    ))}
                </tbody>
            </table>

            <h4 className="mt-5">Payment Hashes</h4>

            <table className="table table-bordered">
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Blockchain Hash</th>
                    </tr>
                </thead>
                <tbody>
                    {payments.map((payment) => (
                        <tr key={payment.id}>
                            <td>{payment.id}</td>
                            <td>{payment.blockchain_hash}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
}

export default BlockchainView;
